    [VectorCombine] Fix crash with poison mask elements in shrinkLoadForShuffles (#178920)

    ## Summary
    Fixes assertion failure when `shrinkLoadForShuffles` processes shuffle
    masks containing poison elements.

    The bug was introduced in #149093 , when adjusting mask indices for load
    trimming, poison indices (-1) were modified to invalid values (e.g.,
    -2), causing `isSingleSourceMaskImpl` to assert.

    The fix preserves poison indices without modification.

    Fixes #178917

    ## Test plan
    - Added regression test `@shuffle_with_poison_mask`

diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index d173afd24e54..c1cca6e28a8e 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -5453,6 +5453,11 @@ bool VectorCombine::shrinkLoadForShuffles(Instruction &I) {
         NewUses.push_back({Shuffle, {}});
         std::vector<int> &NewMask = NewUses.back().second;
         for (int Index : OldMask) {
+          // Preserve poison indices without modification.
+          if (Index == PoisonMaskElem) {
+            NewMask.push_back(Index);
+            continue;
+          }
           int NewIndex = Index >= static_cast<int>(OldNumElements)
                              ? Index - LowOffset - HighOffset
                              : Index - LowOffset;

tests.test_body:
define <8 x i16> @shuffle_with_poison_mask(ptr %p) {
  %pre = load <8 x i16>, ptr %p, align 1
  %shuf = shufflevector <8 x i16> %pre, <8 x i16> poison, <8 x i32> <i32 1, i32 3, i32 poison, i32 poison, i32 poison, i32 5, i32 poison, i32 7>
  ret <8 x i16> %shuf
}

define <16 x i8> @shuffle_v16_v16i8_r0_31(ptr %arg) {
  %load = load <16 x i8>, ptr %arg, align 1
  %shuf = shufflevector <16 x i8> %load, <16 x i8> poison, <16 x i32> <i32 0, i32 1, i32 2, i32 3, i32 4, i32 5, i32 6, i32 7, i32 24, i32 25, i32 26, i32 27, i32 28, i32 29, i32 30, i32 31>
  ret <16 x i8> %shuf
}
